function safeAdd (uint256 _x, uint256 _y) internal pure returns (uint256)

    {
        uint256 z = _x + _y; require (z > = _x); return z;
    }

function safeSub (uint256 _x, uint256 _y) internal pure returns (uint256)

    {
        require (_x > = _y); return _x - _y;
    }

function safeMul (uint256 _x, uint256 _y) internal pure returns (uint256)

    {
        uint256 z = _x * _y; require (_x = = 0 | | z / _x = = _y); return z;
    }

function safeDiv (uint256 _x, uint256 _y) internal pure returns (uint256)

    {
        return _x / _y;
    }

function ceilDiv (uint256 _x, uint256 _y) internal pure returns (uint256)

    {
        return (_x + _y - 1) / _y;
    }

function sqrt (uint x) public pure returns (uint y)

    {
        uint z = (x + 1) / 2; y = x; while (z < y)
        {
            y = z; z = (x / z + z) / 2;
        }

    }

