function calledUpdate (address _oldCalled, address _newCalled) public ownerOnly

    {
        if (data = = _oldCalled)
        {
            data = IData (_newCalled);
        }
        else if (reserve = = _oldCalled)
        {
            reserve = IReserve (_newCalled);
        }
        else if (formula = = _oldCalled)
        {
            formula = IFormula (_newCalled);
        }
        else if (impl = = _oldCalled)
        {
            impl = I$martFundImpl (_newCalled);
        }
        else
        {
            return;
        }
        emit CalledUpdate (_oldCalled, _newCalled);
    }

function updateEmaDailyYieldSF (uint256 _value) internal returns (uint256)

    {
        uint256 ema = getBU ("emaDailyYieldSF"); uint32 timeSpan = uint32 (safeSub (now, getBU ("timeLastMiningSF"))); setBU ("timeLastMiningSF", now); ema = formula.calcEma (ema, _value, timeSpan, 1 days); setBU ("emaDailyYieldSF", ema); return ema;
    }

function checkQuotaPropose (uint256 _eth, uint256 _sf) public view returns (bool)

    {
        uint256 totalSupply_ = formula.totalSupply (); uint256 reserve_ = reserve.balanceOfShares (); if (_sf * 1 ether > totalSupply_ * getBU ("quotaPerProposeSF") | | _eth * 1 ether > reserve_ * getBU ("quotaPerProposeEth")) return false; for (uint256 id
          = getBUU (_projectsVoting_, 0x0); id ! = 0x0; id = getBUU (_projectsVoting_, id))
        {
            _sf + = getBUU (_investmentSF_, id); _eth + = getBUU (_investmentEth_, id);
        }
        return _sf * 1 ether < = totalSupply_ * getBU ("quotaAllProposeSF") & & _eth * 1 ether < = reserve_ * getBU ("quotaAllProposeEth");
    }

function propose (bytes32 _projectID, bytes32 _proposeID, IProject _project, uint256 _eth, uint256 _sf, string _mixInfo) public enabled2

    {
        emit Propose (msg.sender, _proposeID, _projectID, _project, _eth, _sf); IDummyToken $fd = IDummyToken (getBA (_$FD_)); require ($fd.balanceOf (msg.sender) * 1 ether > = $fd.totalSupply () * getBU (_thresholdPropose_)); if (address (_project) ! =
          address (0x0)) require (checkQuotaPropose (_eth, _sf)); if (_projectID = = _proposeID)
        {
            uint256 projectID = getBAU (_projectID_, _project); uint256 status = getBUU (_projectStatus_, projectID); require (projectID = = 0 | | status = = PROJECT_STATUS_FAIL | | status = = PROJECT_STATUS_DISINVESTED); projectID = uint256 (_projectID);
              setBAU (_projectID_, _project, projectID);
        }
        else
        {
            projectID = uint256 (_projectID); require (getBAU (_projectID_, _project) = = projectID); require (getBUU (_projectStatus_, projectID) = = PROJECT_STATUS_INVESTED); uint256 proposeID = getBUU (_proposeID_, projectID); require (proposeID = = 0 |
              | proposeID = = projectID | | getBUU (_projectStatus_, proposeID) ! = PROJECT_STATUS_VOTING); uint256 disproposeID = getBUU (_disproposeID_, projectID); require (disproposeID = = 0 | | getBUU (_projectStatus_, disproposeID) = =
              PROJECT_STATUS_FAIL);
        }
        proposeID = uint256 (_proposeID); require (getBUU (_projectStatus_, proposeID) = = 0x0); setBUU (_proposeID_, projectID, proposeID); setBUU (_projectID_, proposeID, projectID); setBUU (_projectStatus_, proposeID, PROJECT_STATUS_VOTING); setBUU (
          _timePropose_, proposeID, now); setBUA (_projectAddr_, proposeID, _project); setBUU (_investmentSF_, proposeID, _sf); setBUU (_investmentEth_, proposeID, _eth); setBUS (_projectInfo_, proposeID, _mixInfo); setBUU (_projects_, proposeID, getBUU (
          _projects_, 0x0)); setBUU (_projects_, 0x0, proposeID); setBUU (_projectsVoting_, proposeID, getBUU (_projectsVoting_, 0x0)); setBUU (_projectsVoting_, 0x0, proposeID); vote (_proposeID, VOTE_YES);
    }

function dispropose (bytes32 _projectID, bytes32 _disproposeID, string _mixInfo) public enabled2

    {
        emit Dispropose (msg.sender, _projectID, _disproposeID); uint256 projectID = uint256 (_projectID); require (getBUU (_projectStatus_, projectID) = = PROJECT_STATUS_INVESTED); uint256 proposeID = getBUU (_proposeID_, projectID); require (proposeID =
          = 0 | | proposeID = = projectID | | getBUU (_projectStatus_, proposeID) ! = PROJECT_STATUS_VOTING); uint256 disproposeID = getBUU (_disproposeID_, projectID); require (disproposeID = = 0 | | getBUU (_projectStatus_, disproposeID) = =
          PROJECT_STATUS_FAIL); disproposeID = uint256 (_disproposeID); require (getBUU (_projectStatus_, disproposeID) = = 0x0); setBUU (_disproposeID_, projectID, disproposeID); setBUU (_projectID_, disproposeID, projectID); IDummyToken $fd = IDummyToken
          (getBA (_$FD_)); require ($fd.balanceOf (msg.sender) * 1 ether > = $fd.totalSupply () * getBU (_thresholdPropose_)); setBUU (_projectStatus_, disproposeID, PROJECT_STATUS_DISVOTING); setBUU (_timePropose_, disproposeID, now); setBUS (
          _projectInfo_, disproposeID, _mixInfo); setBUU (_projects_, disproposeID, getBUU (_projects_, 0x0)); setBUU (_projects_, 0x0, disproposeID); setBUU (_projectsVoting_, disproposeID, getBUU (_projectsVoting_, 0x0)); setBUU (_projectsVoting_, 0x0,
          disproposeID); vote (_disproposeID, VOTE_YES);
    }

function getVotes (bytes32 _ID, bytes32 _vote) public view returns (uint256)

    {
        return impl.getVotes (_ID, _vote);
    }

function vote (bytes32 _ID, bytes32 _vote) public enabled2

    {
        uint256 status = getBUU (_projectStatus_, uint256 (_ID)); require (status = = PROJECT_STATUS_VOTING | | status = = PROJECT_STATUS_DISVOTING); impl.impl_vote (msg.sender, _ID, _vote);
    }

function voteYes (bytes32 _projectID) public

    {
        vote (_projectID, VOTE_YES);
    }

function voteNo (bytes32 _projectID) public

    {
        vote (_projectID, VOTE_NO);
    }

function voteCancle (bytes32 _projectID) public

    {
        vote (_projectID, VOTE_CANCEL);
    }

function updateProject (address _oldProject, address _newProject) public ownerOnly

    {
        uint256 id = getBAU (_projectID_, _oldProject); setBAU (_projectID_, _newProject, id); setBAU (_projectID_, _oldProject, 0); setBUA (_projectAddr_, id, _newProject); emit UpdateProject (msg.sender, bytes32 (id), _oldProject, _newProject);
    }

function returnProfit (bytes32 _projectID, uint256 _eth, uint256 _sf) public enabled2

    {
        emit ReturnProfit (msg.sender, _projectID, _eth, _sf); uint256 projectID = uint256 (_projectID); if (_sf > 0)
        {
            setBUU (_profitSF_, projectID, safeAdd (getBUU (_profitSF_, projectID), _sf)); setBU (_profitSF_, safeAdd (getBU (_profitSF_), _sf)); uint256 ema = updateEmaDailyYieldSF (_sf); I$FM2_Operator addrMSM2O = I$FM2_Operator (IDummyToken (getBA (
              _$FM2_)).operator ()); uint256 ratioDividend = addrMSM2O.updateRatioDividend (_sf, ema); uint256 dividend = _sf * ratioDividend / 1 ether; uint256 supplyOld = formula.totalSupply (); uint256 supplyNew = safeSub (supplyOld + dividend, _sf);
              uint256 weightOld = getBU (_weightOfReserve_); uint256 weightNew = weightOld * supplyOld / supplyNew; setBU (_weightOfReserve_, weightNew); uint256 reserve_ = reserve.balanceOfShares (); emit Weight ("returnProfit", weightNew, weightOld,
              reserve_, reserve_, supplyNew, supplyOld, reserve_ * 1 ether / weightOld * 1 ether / supplyOld); IDummyToken (getBA (_$F_)).operator ().destroy (getBUA (_projectAddr_, projectID), _sf); addrMSM2O.dividend (dividend); setBU (_returnSF_,
              safeSub (safeAdd (getBU (_returnSF_), _sf), dividend));
        }
        if (_eth > 0)
        {
            setBUU (_profitEth_, projectID, getBUU (_profitEth_, projectID) + _eth); setBU (_profitEth_, getBU (_profitEth_) + _eth); reserve.project2Mineral (_eth); IEtherToken (getBA (_ETHER_)).destroy (getBUA (_projectAddr_, projectID), _eth); setBAU (
              _projectID_, msg.sender, projectID); ITokenOperator (IDummyToken (getBA (_$FM_)).operator ()).issue (msg.sender, _eth); impl.dequeue ("dequeueWhenMining");
        }

    }

function returnDisinvestment (bytes32 _projectID, uint256 _eth, uint256 _sf) public enabled2

    {
        emit ReturnDisinvestment (msg.sender, _projectID, _eth, _sf); setBUU (_projectStatus_, uint256 (_projectID), PROJECT_STATUS_DISINVESTED); setBUU (_disproposeID_, uint256 (_projectID), 0); address project = getBUA (_projectAddr_, uint256 (
          _projectID)); setBAU (_projectID_, project, 0); uint256 supply = formula.totalSupply (); uint256 reserve_ = reserve.balanceOfShares (); if (_sf > 0)
        {
            setBUU (_profitSF_, uint256 (_projectID), safeAdd (getBUU (_profitSF_, uint256 (_projectID)), _sf)); setBU (_profitSF_, safeAdd (getBU (_profitSF_), _sf)); setBU (_returnSF_, safeAdd (getBU (_returnSF_), _sf)); uint256 weightOld = getBU (
              _weightOfReserve_); uint256 weightNew = weightOld * supply / safeSub (supply, _sf); setBU (_weightOfReserve_, weightNew); emit Weight ("returnDisinvestment", weightNew, weightOld, reserve_, reserve_, safeSub (supply, _sf), supply, reserve_ *
              1 ether / weightOld * 1 ether / supply); IDummyToken (getBA (_$F_)).operator ().destroy (project, _sf);
        }
        if (_eth > 0)
        {
            setBUU (_profitEth_, uint256 (_projectID), getBUU (_profitEth_, uint256 (_projectID)) + _eth); setBU (_profitEth_, getBU (_profitEth_) + _eth); setBU (_returnEth_, getBU (_returnEth_) + _eth); weightOld = getBU (_weightOfReserve_); weightNew =
              weightOld * (reserve_ + _eth) / reserve_; setBU (_weightOfReserve_, weightNew); emit Weight ("returnDisinvestment", weightNew, weightOld, reserve_ + _eth, reserve_, supply, supply, reserve_ * 1 ether / weightOld * 1 ether / supply);
              IEtherToken (getBA (_ETHER_)).destroy (project, _eth); reserve.project2Shares (_eth);
        }

    }

function forging (uint256 _msm) public enabled

    {
        return impl.impl_forging (msg.sender, _msm);
    }

function purchase (bool _wantDividend, bool _nonInvate, bytes32 _channel, bytes32 _recommendation) public payable enabled

    {
        if (_recommendation ! = 0) IRecommend (getBA (_Recommend_)).bindRecommenderImpl (msg.sender, _recommendation); if (msg.value > 0) return impl.impl_purchase.value (msg.value) (msg.sender, _wantDividend, _nonInvate, _channel);
    }

function cancelOrder (uint256 _mso) public enabled returns (uint256 eth)

    {
        return impl.impl_cancelOrder (msg.sender, _mso);
    }

