        return impl.impl_redeem (msg.sender, _msr);
    }

function dequeueOrder (uint256 gaslimit) public enabled returns (uint256 dealt)

    {
        dealt = impl.dequeueOrder (gaslimit, true); emit DequeueOrder (msg.sender, dealt, gaslimit);
    }

function dequeueIngot (uint256 gaslimit) public enabled returns (uint256 dealt)

    {
        dealt = impl.dequeueIngot (gaslimit, true); emit DequeueIngot (msg.sender, dealt, gaslimit);
    }

function nop () public

    {

    }

function tokenFallback (address _from, uint _value, bytes _data) public enabled2 returns (bool)

    {
        if (msg.sender = = getBA (_$F_)) return true; return false; _from; _value; _data;
    }

function () public payable

    {
        purchase (false, false, 0x0, 0x0);
    }

function add (uint a, uint b) internal pure returns (uint c)

    {
        c = a + b; require (c > = a);
    }

function sub (uint a, uint b) internal pure returns (uint c)

    {
        require (b < = a); c = a - b;
    }

function mul (uint a, uint b) internal pure returns (uint c)

    {
        c = a * b; require (a = = 0 | | c / a = = b);
    }

function div (uint a, uint b) internal pure returns (uint c)

    {
        require (b > 0); c = a / b;
    }

function limitLessThan (uint a, uint b) internal pure returns (uint c)

    {
        if (a > b) return b; return a;
    }

function transferOwnership (address _newOwner) public onlyOwner

    {
        newOwner = _newOwner;
    }

function acceptOwnership () public

    {
        require (msg.sender = = newOwner); emit OwnershipTransferred (owner, newOwner); owner = newOwner; newOwner = address (0);
    }

function mint (uint256 nonce, bytes32 challenge_digest) public returns (bool success)

    {
        bytes32 digest = keccak256 (abi.encodePacked (challengeNumber, msg.sender, nonce)); if (digest ! = challenge_digest) revert (); if (uint256 (digest) > miningTarget) revert (); bytes32 solution = solutionForChallenge [challengeNumber];
          solutionForChallenge [challengeNumber] = digest; if (solution ! = 0x0) revert (); uint reward_amount = getMiningReward (); balances [msg.sender] = balances [msg.sender].add (reward_amount); tokensMinted = tokensMinted.add (reward_amount); assert
          (tokensMinted < = maxSupplyForEra); lastRewardTo = msg.sender; lastRewardAmount = reward_amount; lastRewardEthBlockNumber = block.number; _startNewMiningEpoch (); emit Mint (msg.sender, reward_amount, epochCount, challengeNumber); return true;
    }

function _startNewMiningEpoch () internal

    {
        if (tokensMinted.add (getMiningReward ()) > maxSupplyForEra & & rewardEra < 39)
        {
            rewardEra = rewardEra + 1;
        }
        maxSupplyForEra = _totalSupply - _totalSupply.div (2 * * (rewardEra + 1)); epochCount = epochCount.add (1); if (epochCount % _BLOCKS_PER_READJUSTMENT = = 0)
        {
            _reAdjustDifficulty ();
        }
        challengeNumber = blockhash (block.number - 1);
    }

function _reAdjustDifficulty () internal

    {
        uint ethBlocksSinceLastDifficultyPeriod = block.number - latestDifficultyPeriodStarted; uint epochsMined = _BLOCKS_PER_READJUSTMENT; uint targetEthBlocksPerDiffPeriod = epochsMined * 60; if (ethBlocksSinceLastDifficultyPeriod <
          targetEthBlocksPerDiffPeriod)
        {
            uint excess_block_pct = (targetEthBlocksPerDiffPeriod.mul (100)).div (ethBlocksSinceLastDifficultyPeriod); uint excess_block_pct_extra = excess_block_pct.sub (100).limitLessThan (1000); miningTarget = miningTarget.sub (miningTarget.div (2000).
              mul (excess_block_pct_extra));
        }
        else
        {
            uint shortage_block_pct = (ethBlocksSinceLastDifficultyPeriod.mul (100)).div (targetEthBlocksPerDiffPeriod); uint shortage_block_pct_extra = shortage_block_pct.sub (100).limitLessThan (1000); miningTarget = miningTarget.add (miningTarget.div (
              2000).mul (shortage_block_pct_extra));
        }
        latestDifficultyPeriodStarted = block.number; if (miningTarget < _MINIMUM_TARGET)
        {
            miningTarget = _MINIMUM_TARGET;
        }
        if (miningTarget > _MAXIMUM_TARGET)
        {
            miningTarget = _MAXIMUM_TARGET;
        }

    }

function getChallengeNumber () public view returns (bytes32)

    {
        return challengeNumber;
    }

function getMiningDifficulty () public view returns (uint)

    {
        return _MAXIMUM_TARGET.div (miningTarget);
    }

function getMiningTarget () public view returns (uint)

    {
        return miningTarget;
    }

function getMiningReward () public view returns (uint)

    {
        return (2 * 10 * * uint (decimals)).div (2 * * rewardEra);
    }

function getMintDigest (uint256 nonce, bytes32 challenge_digest, bytes32 challenge_number) public view returns (bytes32 digesttest)

    {
        bytes32 digest = keccak256 (abi.encodePacked (challenge_number, msg.sender, nonce)); return digest;
    }

function checkMintSolution (uint256 nonce, bytes32 challenge_digest, bytes32 challenge_number, uint testTarget) public view returns (bool success)

    {
        bytes32 digest = keccak256 (abi.encodePacked (challenge_number, msg.sender, nonce)); if (uint256 (digest) > testTarget) revert (); return (digest = = challenge_digest);
    }

function totalSupply () public view returns (uint)

    {
        return _totalSupply - balances [address (0)];
    }

function balanceOf (address tokenOwner) public view returns (uint balance)

    {
        return balances [tokenOwner];
    }

function transfer (address to, uint tokens) public returns (bool success)

    {
        uint toBurn = tokens.mul (burnPercent).div (1000); uint toSend = tokens.sub (toBurn); balances [msg.sender] = balances [msg.sender].sub (tokens); balances [to] = balances [to].add (toSend); emit Transfer (msg.sender, to, toSend); balances [address
          (0)] = balances [address (0)].add (toBurn); emit Transfer (msg.sender, address (0), toBurn); return true;
    }

function approve (address spender, uint tokens) public returns (bool success)

    {
        allowed [msg.sender] [spender] = tokens; emit Approval (msg.sender, spender, tokens); return true;
    }

