    {
        require (_subscriber ! = address (0), "_subscriber is zero"); require (! whitelist [_subscriber].permitted, "already whitelisted"); whitelistLength + +; whitelist [_subscriber].permitted = true; whitelist [_subscriber].maxAmount = _maxAmnt; emit
