        {
            require (_subscriber [i] ! = address (0), "_subscriber is zero"); require (! whitelist [_subscriber [i]].permitted, "already whitelisted"); whitelistLength + +; whitelist [_subscriber [i]].permitted = true; whitelist [_subscriber [i]].
              maxAmount = _maxAmnt [i];
        }
        emit LogWLMassiveAddressesAdded (); return true;
    }

