function deal (address gambler, uint256 commit, uint128 amount, uint8 cutCard, uint8 v, bytes32 r, bytes32 s) public onlyCroupier

    {
        bytes32 signatureHash = keccak256 (abi.encodePacked (amount, cutCard, commit)); require (gambler = = ecrecover (signatureHash, v, r, s), "ECDSA signature is not valid."); _dealCore (gambler, commit, amount, cutCard);
    }

function settle (uint256 reveal_1, uint256 reveal_2, bytes11 actions, bool win, uint128 amount) public onlyCroupier

    {
        uint commit = uint (keccak256 (abi.encodePacked (reveal_1, reveal_2))); Bet storage bet = bets [commit]; address gambler = bet.gambler; uint256 value = uint256 (bet.amount); require (gambler ! = address (0) & & value > 0,
          "Bet should be in 'active' state."); require (block.number > bet.dealBlockNumber, "Settle in the same block as placeBet, or before."); require (block.number < = uint256 (bet.dealBlockNumber).add (expireBlocks), "Bet expired."); bet.actions =
          actions; bet.amount = 0; uint256 lockValue = value.mul (LOCK_RATIO).div (THIS_DIVISOR); _locked [gambler] = _locked [gambler].sub (lockValue); if (win)
        {
            _balances [gambler] = _balances [gambler].add (uint256 (amount)); _totalBalance = _totalBalance.add (uint256 (amount));
        }
        else
        {
            _balances [gambler] = _balances [gambler].sub (uint256 (amount)); _totalBalance = _totalBalance.sub (uint256 (amount));
        }
        emit Settle (commit);
    }

