          expireBlocks), "Bet not yet expired."); uint256 lockValue = value.mul (LOCK_RATIO).div (THIS_DIVISOR); _locked [gambler] = _locked [gambler].sub (lockValue); bet.amount = 0; emit Refund (commit, uint128 (value));
    }

