function _withdraw (address from, uint256 value) internal

    {
        require (from ! = address (0), "Invalid address."); require (value < = _balances [from].sub (_locked [from]), "Not enough balance."); _balances [from] = _balances [from].sub (value); _totalBalance = _totalBalance.sub (value); uint256 fee = value.
          mul (feeRatio).div (THIS_DIVISOR); require (value.sub (fee) < = address (this).balance, "Can't afford."); from.transfer (value.sub (fee)); emit Withdraw (from, value);
