function _dealCore (address gambler, uint256 commit, uint128 amount, uint8 cutCard) internal

    {
        Bet storage bet = bets [commit]; require (bet.gambler = = address (0), "Bet should be in 'clean' state."); require (cutCard < = MAX_CUT_CARD, "Cut card position is not valid."); uint256 value = uint256 (amount); require (_safeTypeConversion (value
          , amount), "Not safe type conversion"); require (value > = minBet & & value < = maxBet, "Bet amount is out of range."); uint256 lockValue = value.mul (LOCK_RATIO).div (THIS_DIVISOR); require (lockValue < = balanceOf (gambler).sub (lockedOf (
          gambler)), "Balance is not enough for locked."); _locked [gambler] = _locked [gambler].add (lockValue); bet.gambler = gambler; bet.cutCard = cutCard; bet.amount = amount; bet.dealBlockNumber = uint128 (block.number); emit Deal (commit);
