        require (periods [_prevHash].timestamp > 0, "Parent node should exist"); require (periods [_root].timestamp = = 0, "Trying to submit the same root twice"); newHeight = periods [_prevHash].height + 1; if (newHeight > periods [tipHash].height)
        {
