function calculateWithdrawable () public view returns (uint withdrawable)

    {
        uint timePassed = block.timestamp.sub (vestingStartTime); if (timePassed < vestingPeriod)
        {
            uint vested = totalVestingAmount.mul (timePassed).div (vestingPeriod); withdrawable = vested.sub (withdrawn);
        }
        else
        {
            withdrawable = totalVestingAmount.sub (withdrawn);
        }

    }

function setVesting (address ofBeneficiary, uint ofMelonQuantity, uint ofVestingPeriod) external only_owner not_interrupted vesting_not_started

    {
        require (ofMelonQuantity > 0, "Must vest some MLN"); require (MELON_CONTRACT.transferFrom (msg.sender, this, ofMelonQuantity), "MLN deposit failed"); isVestingStarted = true; vestingStartTime = block.timestamp; totalVestingAmount = ofMelonQuantity
          ; vestingPeriod = ofVestingPeriod; beneficiary = ofBeneficiary;
    }

function withdraw () external only_beneficiary vesting_started not_interrupted

    {
        uint withdrawable = calculateWithdrawable (); withdrawn = withdrawn.add (withdrawable); require (MELON_CONTRACT.transfer (beneficiary, withdrawable), "Transfer to beneficiary failed");
    }

function forceWithdrawalAndInterrupt () external only_owner vesting_started not_interrupted

    {
        interrupted = true; uint remainingVested = calculateWithdrawable (); uint totalToBeVested = withdrawn.add (remainingVested); uint remainingUnvested = totalVestingAmount.sub (totalToBeVested); withdrawn = totalVestingAmount; require (MELON_CONTRACT
          .transfer (beneficiary, remainingVested), "Transfer to beneficiary failed"); require (MELON_CONTRACT.transfer (owner, remainingUnvested), "Transfer to owner failed");
    }

