function startPreSale () public onlyOwner onlyInState (State.Init)

    {
        setState (State.PreSale); preSaleStartTime = uint64 (now); token.lockTransfer (true);
    }

function startPreICO () public onlyOwner onlyInState (State.PreSale)

    {
        require (now > = preSaleStartTime + 1 days, "Mimimum period Pre-Sale is 10 days"); setState (State.PreICO); preICOStartTime = uint64 (now);
    }

function startCrowdSale () public onlyOwner onlyInState (State.PreICO)

    {
        require (now > = preICOStartTime + 1 days, "Mimimum period Pre-ICO is 15 days"); setState (State.CrowdSale); crowdSaleStartTime = uint64 (now);
    }

function finishCrowdSale () public onlyOwner onlyInState (State.CrowdSale)

    {
        require (now > = crowdSaleStartTime + 1 days, "Mimimum period CrowdSale is 30 days"); if (soldTokens < TOKEN_SOFT_CAP)
        {
            setState (State.Refunding);
        }
        else
        {
            setState (State.WorkTime); token.lockTransfer (false);
        }

    }

function blockExternalTransfer () public onlyOwner onlyInState (State.WorkTime)

    {
        require (token.lockTransfers () = = false); token.lockTransfer (true);
    }

function unBlockExternalTransfer () public onlyOwner onlyInState (State.WorkTime)

    {
        require (token.lockTransfers () = = true); token.lockTransfer (false);
    }

function calcBonus () public view returns (uint256)

    {
        uint256 actualBonus = 0; if (currentState = = State.PreSale)
        {
            actualBonus = 20;
        }
        if (currentState = = State.PreICO)
        {
            actualBonus = 10;
        }
        return actualBonus;
    }

function saleTokens () internal

    {
        require (currentState ! = State.Init, "Contract is init, do not accept ether."); require (currentState ! = State.Refunding, "Contract is refunding, do not accept ether."); require (currentState ! = State.WorkTime,
          "Contract is WorkTime, do not accept ether."); if (currentState = = State.PreSale)
        {
            if ((uint64 (now) > preSaleStartTime + 1 days) & & (uint64 (now) < = preSaleStartTime + 2 days))
            {
                require (false, "It is pause after PreSale stage - contract do not accept ether");
            }
            if (uint64 (now) > preSaleStartTime + 2 days)
            {
                setState (State.PreICO); preICOStartTime = uint64 (now);
            }

        }
        if (currentState = = State.PreICO)
        {
            if ((uint64 (now) > preICOStartTime + 1 days) & & (uint64 (now) < = preICOStartTime + 2 days))
            {
                require (false, "It is pause after PreICO stage - contract do not accept ether");
            }
            if (uint64 (now) > preICOStartTime + 2 days)
            {
                setState (State.CrowdSale); crowdSaleStartTime = uint64 (now);
            }

        }
        if (currentState = = State.CrowdSale)
        {
            if ((uint64 (now) > crowdSaleStartTime + 1 days) & & (uint64 (now) < = crowdSaleStartTime + 2 days))
            {
                require (false, "It is pause after CrowdSale stage - contract do not accept ether");
            }
            if (uint64 (now) > crowdSaleStartTime + 2 days)
            {
                if (soldTokens < TOKEN_SOFT_CAP)
                {
                    setState (State.Refunding);
                }
                else
                {
                    setState (State.WorkTime); token.lockTransfer (false);
                }

            }

        }
        uint tokens = saleRate.mul (msg.value); if (currentState = = State.PreSale)
        {
            require (RPESALE_TOKEN_SUPPLY_LIMIT > soldTokens.add (tokens), "HardCap of Pre-Sale is excedded."); require (msg.value > = 1 ether / 10, "Minimum 20 ether for transaction all Pre-Sale period");
        }
        if (currentState = = State.PreICO)
        {
            require (RPEICO_TOKEN_SUPPLY_LIMIT > soldTokens.add (tokens), "HardCap of Pre-ICO is excedded."); if (uint64 (now) < preICOStartTime + 1 days)
            {
                uint limitPerUser = crowdsaleBalances [msg.sender] + msg.value; require (limitPerUser < = 1 ether / 10, "Maximum is 20 ether for user in first day of Pre-ICO");
            }

        }
        tokens = tokens.add (tokens.mul (calcBonus ()).div (100)); crowdsaleBalances [msg.sender] = crowdsaleBalances [msg.sender].add (msg.value); token.transfer (msg.sender, tokens); soldTokens = soldTokens.add (tokens);
    }

function refund () public payable

    {
        require (currentState = = State.Refunding, "Only for Refunding stage."); uint value = crowdsaleBalances [msg.sender]; crowdsaleBalances [msg.sender] = 0; msg.sender.transfer (value); emit Refunding (msg.sender, value);
    }

function withdrawProfit (address payable _to, uint256 _value) public onlyOwner payable

