function toTimestamp (uint16 year, uint8 month, uint8 day, uint8 hour, uint8 minute, uint8 second) public pure returns (uint timestamp)

    {
        uint16 i; for (i = ORIGIN_YEAR; i < year; i + +)
        {
            if (isLeapYear (i))
            {
                timestamp + = LEAP_YEAR_IN_SECONDS;
            }
            else
            {
                timestamp + = YEAR_IN_SECONDS;
            }

        }
        uint8 [12] memory monthDayCounts; monthDayCounts [0] = 31; if (isLeapYear (year))
        {
            monthDayCounts [1] = 29;
        }
        else
        {
            monthDayCounts [1] = 28;
        }
        monthDayCounts [2] = 31; monthDayCounts [3] = 30; monthDayCounts [4] = 31; monthDayCounts [5] = 30; monthDayCounts [6] = 31; monthDayCounts [7] = 31; monthDayCounts [8] = 30; monthDayCounts [9] = 31; monthDayCounts [10] = 30; monthDayCounts [11] =
          31; for (i = 1; i < month; i + +)
        {
            timestamp + = DAY_IN_SECONDS * monthDayCounts [i - 1];
