                _totalFee = _totalFee.add (lottery.remainder);
            }
            lottery.remainder = 0; _totalFee = _totalFee.add (_reservedFee [lottery.id]); _reservedFee [lottery.id] = 0; lottery.isPayedOut = true; removeLotteryIdFromArray (lottery.id, _unpayedLotteries);
        }

    }

function deleteLottery (uint256 lotteryId) public onlyOwner

    {
        require (lotteryId < = _lastLotteryId); Lottery storage lottery = _lotteries [lotteryId]; require (lottery.status = = LotteryStatus.Open); require (lottery.isContinued); lottery.isContinued = false; emit DeleteLotteryEvent (lotteryId);
    }

function createOrder (address recipient, uint256 part, uint256 sum, uint256 expiredDate) public onlyAdmin

    {
        require (_adminsParts [msg.sender] > = part); require (expiredDate > now); _lastOrderId = _lastOrderId.add (1); _orders [_lastOrderId] = Order ({id : _lastOrderId, admin : msg.sender, recipient : recipient, part : part, sum : sum, expiredDate :
          expiredDate, status : OrderStatus.Open}); emit NewOrderEvent (_lastOrderId, msg.sender, recipient);
    }

function confirmOrder (uint256 orderId) public payable

    {
        require (orderId < = _lastOrderId); Order storage order = _orders [orderId]; require (msg.sender = = order.recipient); require (order.expiredDate > now); require (order.status = = OrderStatus.Open); require (msg.value > = order.sum); require (
          order.part < = _adminsParts [order.admin]); if (! checkIsAdmin (msg.sender))
        {
            _admins.push (msg.sender);
        }
        distributeDividend (); _adminsParts [order.admin] = _adminsParts [order.admin].sub (order.part); _adminsParts [msg.sender] = _adminsParts [msg.sender].add (order.part); if (_adminsParts [order.admin] = = 0)
        {
            removeAdmin (order.admin);
        }
        address payable addr = address (uint160 (order.admin)); addr.transfer (order.sum); uint256 remainder = msg.value.sub (order.sum); if (remainder > 0) msg.sender.transfer (remainder); order.status = OrderStatus.Closed; emit ConfirmOrderEvent (order.
          id);
    }

