function removeAdmin (address addr) private

    {
        require (checkIsAdmin (addr)); require (_adminsParts [addr] = = 0); uint256 index; for (uint256 i = 0; i < _admins.length; i + +)
        {
            if (_admins [i] = = addr)
            {
                index = i; break;
            }

        }
        for (uint256 i = index; i < _admins.length.sub (1); i + +)
        {
            _admins [i] = _admins [i.add (1)];
        }
        _admins.length - -;
