function addPlayerToLottery (Lottery memory lottery, uint256 sum) private

    {
        require (lottery.begin < = now & & lottery.end > = now); require (lottery.status = = LotteryStatus.Open); Player memory player = Player ({addr : msg.sender, blockNumber : block.number, sum : sum, prize : 0}); _players [lottery.id].push (player);
    }

function createChildLottery (Lottery storage parentLottery) private

    {
        if (! parentLottery.isContinued) return; uint256 period = parentLottery.end.sub (parentLottery.begin); uint256 begin = parentLottery.end; uint256 end = begin.add (period); if (end < now) (begin, end) = getPeriodBorders (begin, end, now);
          _lastLotteryId = _lastLotteryId.add (1); _lotteries [_lastLotteryId] = Lottery ({id : _lastLotteryId, name : parentLottery.name, owner : msg.sender, price : parentLottery.price, begin : begin, end : end, number : parentLottery.number.add (1), pot
          : 0, status : LotteryStatus.Open, prizeType : parentLottery.prizeType, parentId : parentLottery.id, childId : None, isContinued : parentLottery.isContinued, winNumber : 0, blockNumberForRandom : 0, blockHashForRandom : 0x0, withDiscount :
          parentLottery.withDiscount, winningsCount : None, isPayedOut : false, alreadyPayedCount : 0, remainder : 0}); parentLottery.childId = _lastLotteryId; _openLotteries.push (_lastLotteryId); emit NewLotteryEvent (_lastLotteryId);
    }

function getPeriodBorders (uint256 begin, uint256 end, uint256 currentTime) private pure returns (uint256, uint256)

    {
        if (end < currentTime)
        {
            uint256 period = end.sub (begin); uint256 n = currentTime.sub (end); n = n.div (period); n = n.add (1); uint256 delta = n.mul (period); begin = begin.add (delta); end = end.add (delta);
        }
        return (begin, end);
    }

function finalizeLottery (Lottery storage lottery) private

    {
        beforeFinalizeLottery (lottery); uint256 count = _uniquePlayersCount [lottery.id]; if (count = = 0)
        {
            finalizeEmptyLottery (lottery);
        }
        else if (count = = 1)
        {
            finalizeOnePlayerLottery (lottery);
        }
        else
        {
            finalizeNotEmptyLottery (lottery);
        }
        afterFinalizeLottery (lottery);
    }

function beforeFinalizeLottery (Lottery storage lottery) private

    {
        lottery.status = LotteryStatus.Finished; removeLotteryIdFromArray (lottery.id, _openLotteries);
    }

function afterFinalizeLottery (Lottery storage lottery) private

    {
        emit FinishedLotteryEvent (lottery.id); if (lottery.isContinued) createChildLottery (lottery);
    }

function finalizeEmptyLottery (Lottery storage lottery) private

    {

    }

function finalizeOnePlayerLottery (Lottery storage lottery) private

    {
        require (_players [lottery.id].length > 0); uint256 sum = 0; sum = sum.add (lottery.pot); sum = sum.add (_reservedFee [lottery.id]); _reservedFee [lottery.id] = 0; address payable addr = address (uint160 (_players [lottery.id] [0].addr)); addr.
          transfer (sum);
    }

function finalizeNotEmptyLottery (Lottery storage lottery) private

    {
        (lottery.winNumber, lottery.blockNumberForRandom, lottery.blockHashForRandom) = getWinNumber (lottery); if (lottery.prizeType = = LotteryPrizeType.Three)
        {
            lottery.winningsCount = getWinningsCountForThree (lottery);
        }
        else
        {
            lottery.winningsCount = getWinningsCount (lottery);
        }
        lottery.remainder = lottery.pot; _unpayedLotteries.push (lottery.id);
    }

function incUniquePlayersCount (uint256 lotteryId, address addr) private

    {
        bool isUniq = true; for (uint256 i = 0; i < _players [lotteryId].length; i + +)
        {
            if (addr = = _players [lotteryId] [i].addr)
            {
                isUniq = false; break;
            }

        }
        if (isUniq) _uniquePlayersCount [lotteryId] = _uniquePlayersCount [lotteryId].add (1);
    }

function removeLotteryIdFromArray (uint256 lotteryId, uint256 [] storage array) private

    {
        bool exists = false; uint256 index; for (uint256 i = 0; i < array.length; i + +)
        {
            if (array [i] = = lotteryId)
            {
                index = i; exists = true; break;
            }

        }
        require (exists); for (uint256 i = index; i < array.length.sub (1); i + +)
        {
            array [i] = array [i.add (1)];
        }
        array.length - -;
    }

function getWinningsCount (Lottery memory lottery) private view returns (uint256)

    {
        require (_players [lottery.id].length > 0); uint256 result; uint256 remainder = 0; uint256 playersCount = _players [lottery.id].length; if (lottery.prizeType = = LotteryPrizeType.First)
        {
            result = 1;
        }
        else if (lottery.prizeType = = LotteryPrizeType.All)
        {
            result = _players [lottery.id].length;
        }
        else if (lottery.prizeType = = LotteryPrizeType.T10)
        {
            remainder = playersCount.mod (10); result = playersCount.div (10);
        }
        else if (lottery.prizeType = = LotteryPrizeType.T30)
        {
            result = playersCount.mul (30); remainder = result.mod (100); result = result.div (100);
        }
        else if (lottery.prizeType = = LotteryPrizeType.T50)
        {
            result = playersCount.mul (50); remainder = result.mod (100); result = result.div (100);
        }
        else
        {
            revert ();
        }
        if (remainder > 0 & & result < playersCount)
        {
            result = result.add (1);
        }
        return result;
    }

function getWinningsCountForThree (Lottery memory lottery) private view returns (uint256)

    {
        uint256 result; if (_players [lottery.id].length < 3) result = 1; else result = 3; return result;
    }

function getWinNumber (Lottery memory lottery) private view returns (uint256, uint256, bytes32)

    {
        require (lottery.end < now); require (_players [lottery.id].length > 0); uint256 lastIndex = _players [lottery.id].length.sub (1); uint256 blockNumber = _players [lottery.id] [lastIndex].blockNumber; if (block.number.sub (blockNumber) >
          MAX_RECENT_BLOCK_NUMBER) blockNumber = block.number.sub (MAX_RECENT_BLOCK_NUMBER); else blockNumber = blockNumber.add (1); bytes32 hash = blockhash (blockNumber); return (getRandomNumber (hash, _players [lottery.id].length), blockNumber, hash);
    }

function getRandomNumber (bytes32 hash, uint256 n) private pure returns (uint256)

    {
        return uint256 (keccak256 (abi.encodePacked (hash))).mod (n);
    }

function getActualLotteryPrice (Lottery memory lottery) private view returns (uint256)

    {
        if (! lottery.withDiscount) return lottery.price; uint256 discount = 0; uint256 percent = 0; (uint256 b1, uint256 b2, uint256 b3) = splitPeriod (lottery.begin, lottery.end); if (lottery.begin < = now & & now < b1)
        {
            percent = 300;
        }
        else if (b1 < = now & & now < b2)
        {
            percent = 200;
        }
        else if (b2 < = now & & now < b3)
        {
            percent = 100;
        }
        discount = lottery.price.mul (percent).div (MAX_PERCENTS); return lottery.price.sub (discount);
    }

function splitPeriod (uint256 begin, uint256 end) private pure returns (uint256, uint256, uint256)

    {
        require (begin < end); uint256 step = (end.sub (begin)).div (4); uint256 b1 = begin.add (step); uint256 b2 = b1.add (step); uint256 b3 = b2.add (step); return (b1, b2, b3);
    }

function getShareOfWinnings (uint256 n) private pure returns (uint256 [] memory)

    {
        uint256 [] memory result = new uint256 [] (n); uint256 divider = n.mul (n.add (1)); for (uint256 k = 0; k < n; k + +)
        {
            uint256 p = (n.sub (k)).mul (20000); p = p.div (divider); result [k] = p;
        }
        return result;
    }

function getShareOfWinningsForThree (uint256 n) private pure returns (uint256 [] memory)

    {
        require (n = = 1 | | n = = 3); uint256 [] memory result = new uint256 [] (n); if (n = = 1)
        {
            result [0] = 10000;
        }
        else
        {
            result [0] = 5000; result [1] = 3500; result [2] = 1500;
        }
        return result;
    }

function getToPayCount (uint256 winningsCount, uint256 alreadyPayedCount) private pure returns (uint256)

    {
        uint256 toPayCount = 0; if (winningsCount.sub (alreadyPayedCount) < = TRANSACTIONS_PER_PAYOUT)
        {
            toPayCount = winningsCount.sub (alreadyPayedCount);
        }
        else
        {
            toPayCount = TRANSACTIONS_PER_PAYOUT;
        }
        return toPayCount;
    }

