function updateBalanceAndReserve (address token, address user, uint256 balance, uint256 reserve) private

    {
        uint256 character = uint256 (balance); character | = reserve < < 128; balances [token] [user] = character;
    }

function updateBalance (address token, address user, uint256 balance) private returns (bool)

    {
        uint256 character = uint256 (balance); character | = getReserve (token, user) < < 128; balances [token] [user] = character; return true;
    }

function updateReserve (address token, address user, uint256 reserve) private

    {
        uint256 character = uint256 (balanceOf (token, user)); character | = reserve < < 128; balances [token] [user] = character;
    }

function decodeBalanceAndReserve (address token, address user) returns (uint256 [2])

    {
        uint256 character = balances [token] [user]; uint256 balance = uint256 (uint128 (character)); uint256 reserve = uint256 (uint128 (character > > 128)); return [balance, reserve];
    }

function futuresContractAllowed (address futuresContract, address user) returns (bool)

    {
        if (fistFuturesContract = = futuresContract) return true; if (userAllowedFuturesContracts [user] [futuresContract] = = true) return true; if (futuresContractsAddedBlock [futuresContract] < userFirstDeposits [user]) return true; return false;
    }

function balanceOf (address token, address user) view returns (uint256)

    {
        return decodeBalanceAndReserve (token, user) [0];
    }

function getReserve (address token, address user) public view returns (uint256)

    {
        return decodeBalanceAndReserve (token, user) [1];
    }

function setReserve (address token, address user, uint256 amount) onlyFuturesContract returns (bool success)

    {
        if (! futuresContractAllowed (msg.sender, user)) throw; if (availableBalanceOf (token, user) < amount) throw; updateReserve (token, user, amount); return true;
    }

function setBalance (address token, address user, uint256 amount) onlyFuturesContract returns (bool success)

    {
        if (! futuresContractAllowed (msg.sender, user)) throw; updateBalance (token, user, amount); return true;
    }

function subBalanceAddReserve (address token, address user, uint256 subBalance, uint256 addReserve) onlyFuturesContract returns (bool)

    {
        if (! futuresContractAllowed (msg.sender, user)) throw; updateBalanceAndReserve (token, user, safeSub (balanceOf (token, user), subBalance), safeAdd (getReserve (token, user), addReserve));
    }

function addBalanceSubReserve (address token, address user, uint256 addBalance, uint256 subReserve) onlyFuturesContract returns (bool)

    {
        if (! futuresContractAllowed (msg.sender, user)) throw; updateBalanceAndReserve (token, user, safeAdd (balanceOf (token, user), addBalance), safeSub (getReserve (token, user), subReserve));
    }

function subBalanceSubReserve (address token, address user, uint256 subBalance, uint256 subReserve) onlyFuturesContract returns (bool)

    {
        if (! futuresContractAllowed (msg.sender, user)) throw; updateBalanceAndReserve (token, user, safeSub (balanceOf (token, user), subBalance), safeSub (getReserve (token, user), subReserve));
    }

function availableBalanceOf (address token, address user) view returns (uint256)

    {
        return safeSub (balanceOf (token, user), getReserve (token, user));
    }

function getInactivityReleasePeriod () view returns (uint256)

    {
        return inactivityReleasePeriod;
    }

function addBalance (address token, address user, uint256 amount) private

    {
        updateBalance (token, user, safeAdd (balanceOf (token, user), amount));
    }

function subBalance (address token, address user, uint256 amount) private

    {
        if (availableBalanceOf (token, user) < amount) throw; updateBalance (token, user, safeSub (balanceOf (token, user), amount));
    }

function deposit () payable

    {
        addBalance (address (0), msg.sender, msg.value); if (userFirstDeposits [msg.sender] = = 0) userFirstDeposits [msg.sender] = block.number; lastActiveTransaction [msg.sender] = block.number; emit Deposit (address (0), msg.sender, msg.value, balanceOf
          (address (0), msg.sender));
    }

function depositForUser (address user) payable

    {
        addBalance (address (0), user, msg.value); if (userFirstDeposits [user] = = 0) userFirstDeposits [user] = block.number; lastActiveTransaction [user] = block.number; emit Deposit (address (0), user, msg.value, balanceOf (address (0), user));
    }

function depositToken (address token, uint128 amount)

    {
        addBalance (token, msg.sender, amount); if (userFirstDeposits [msg.sender] = = 0) userFirstDeposits [msg.sender] = block.number; lastActiveTransaction [msg.sender] = block.number; if (! Token (token).transferFrom (msg.sender, this, amount)) throw;
          emit Deposit (token, msg.sender, amount, balanceOf (token, msg.sender));
    }

function depositToken (address token, uint128 amount, address user)

    {
        addBalance (token, user, amount); if (userFirstDeposits [user] = = 0) userFirstDeposits [user] = block.number; lastActiveTransaction [user] = block.number; if (! Token (token).transferFrom (msg.sender, this, amount)) throw; emit Deposit (token,
          user, amount, balanceOf (token, user));
    }

function withdraw (address token, uint256 amount) returns (bool success)

    {
        if (availableBalanceOf (token, msg.sender) < amount) throw; subBalance (token, msg.sender, amount); if (token = = address (0))
        {
            if (! msg.sender.send (amount)) throw;
        }
        else
        {
            if (! Token (token).transfer (msg.sender, amount)) throw;
        }
        emit Withdraw (token, msg.sender, amount, balanceOf (token, msg.sender), 0);
    }

function userAllowFuturesContract (address futuresContract)

    {
