        require (msg.value > 0); uint256 _sendAmount = (msg.value * 2) / 5; require (_sendAmount > 0); uint256 _ethTraderCollateral = msg.value - _sendAmount; Swap memory swap = Swap ({swapState : States.INITIALIZED, sendAmount : _sendAmount, ethTrader :
          msg.sender, fiatTrader : _fiatTrader, openTime : now, ethTraderCollateral : _ethTraderCollateral, fiatTraderCollateral : 0, feeAmount : 0}); swaps [_tradeID] = swap; emit Open (_tradeID, _fiatTrader, _sendAmount);
