function closeSwap (bytes32 _tradeID) public onlyActiveSwaps (_tradeID)

    {
        Swap storage swap = swaps [_tradeID]; require (msg.sender = = swap.ethTrader); swap.swapState = States.CLOSED; uint256 feeAmount = 0; uint256 currentTime = now; if (swap.openTime + 86400 * feeDelay < currentTime)
        {
            uint256 seconds_over = currentTime - (swap.openTime + 86400 * feeDelay); uint256 feePercent = (dailyFeeIncrease * seconds_over) / 86400; if (feePercent > 0)
            {
                if (feePercent > 99000)
                {
                    feePercent = 99000;
                }
