function releaseTimeLock (address _holder) internal returns (bool)

    {
        require (locks [_holder]); uint256 releaseAmount = 0; if (lockupInfo [_holder].lockupBalance < = lockupInfo [_holder].unlockAmountPerMonth)
        {
            releaseAmount = lockupInfo [_holder].lockupBalance; delete lockupInfo [_holder]; locks [_holder] = false;
        }
        else
        {
            releaseAmount = lockupInfo [_holder].unlockAmountPerMonth; lockupInfo [_holder].releaseTime = lockupInfo [_holder].releaseTime.add (MONTH); lockupInfo [_holder].lockupBalance = lockupInfo [_holder].lockupBalance.sub (releaseAmount);
        }
        emit Unlock (_holder, releaseAmount); balances [_holder] = balances [_holder].add (releaseAmount); return true;
    }

