function createLoanApplication (uint256 mortageKgcValue, uint256 duration, uint256 wantValue, uint256 interest) public

    {
        address from = msg.sender; require (kgcInstance.transferFrom (from, address (this), mortageKgcValue)); uint256 transId = totalTrans; LoanTrans memory trans = LoanTrans ({id : transId, status : LoanStatus.STATUS_FRESH, mortageKgcValue :
          mortageKgcValue, duration : duration, wantValue : wantValue, interest : interest, mortager : from, loanStartedAt : 0, lender : address (0)}); totalTrans = totalTrans.add (1); loanTrans.push (trans); emit LoanCreated (transId, from,
          mortageKgcValue, duration, wantValue, interest, now);
    }

function lendTo (uint256 tid) public validateTid (tid) payable

    {
        LoanTrans storage trans = loanTrans [tid]; require (trans.status = = LoanStatus.STATUS_FRESH); require (msg.value = = trans.wantValue); trans.loanStartedAt = now; trans.status = LoanStatus.STATUS_LENDED; trans.lender = msg.sender; address payable
          mortagerAddr = address (uint160 (trans.mortager)); mortagerAddr.transfer (trans.wantValue); emit LoanLended (tid, msg.sender, now);
    }

function paybackTo (uint256 tid) public validateTid (tid) payable

    {
        LoanTrans storage trans = loanTrans [tid]; require (trans.status = = LoanStatus.STATUS_LENDED); require (msg.value = = trans.wantValue.add (trans.interest)); address payable lenderAddr = address (uint160 (trans.lender)); lenderAddr.transfer (msg.
          value); require (kgcInstance.transfer (trans.mortager, trans.mortageKgcValue)); trans.status = LoanStatus.STATUS_PAYBACKED; emit LoanPayed (tid, now);
    }

function forceGetMortage (uint256 tid) public validateTid (tid) payable

    {
        LoanTrans storage trans = loanTrans [tid]; require (now < trans.loanStartedAt.add (trans.duration).add (buffPeriod)); trans.status = LoanStatus.STATUS_MORTAGE_FORCE_TAKED; require (kgcInstance.transfer (trans.lender, trans.mortageKgcValue));
    }

function cancelApplication (uint256 tid) public validateTid (tid) payable

    {
        LoanTrans storage trans = loanTrans [tid]; require (trans.status = = LoanStatus.STATUS_FRESH); require (msg.sender = = trans.mortager); require (kgcInstance.transfer (trans.mortager, trans.mortageKgcValue)); trans.status = LoanStatus.
          STATUS_CANCELD; emit LoanCanceld (tid, now);
    }

