            {
                throw;
            }

        }
        if (investedAmountOf [receiver] = = 0)
        {
            investorCount + +;
        }
        investedAmountOf [receiver] = investedAmountOf [receiver].plus (weiAmount); tokenAmountOf [receiver] = tokenAmountOf [receiver].plus (tokenAmount); weiRaised = weiRaised.plus (weiAmount); tokensSold = tokensSold.plus (tokenAmount); if (
          isBreakingCap (weiAmount, tokenAmount, weiRaised, tokensSold))
