function confirmAndCheck (bytes32 _operation) internal onlyOwner returns (bool)

    {
        if (512 = = m_multiOwnedPendingIndex.length) clearPending (); MultiOwnedOperationPendingState storage pending = m_multiOwnedPending [_operation]; if (! isOperationActive (_operation))
        {
            pending.yetNeeded = m_multiOwnedRequired; pending.ownersDone = 0; pending.index = m_multiOwnedPendingIndex.length + +; m_multiOwnedPendingIndex [pending.index] = _operation; assertOperationIsConsistent (_operation);
        }
        uint256 ownerIndexBit = makeOwnerBitmapBit (msg.sender); if (pending.ownersDone & ownerIndexBit = = 0)
        {
            assert (pending.yetNeeded > 0); if (pending.yetNeeded = = 1)
            {
                delete m_multiOwnedPendingIndex [m_multiOwnedPending [_operation].index]; delete m_multiOwnedPending [_operation]; emit FinalConfirmation (msg.sender, _operation); return true;
            }
            else
            {
                pending.yetNeeded - -; pending.ownersDone | = ownerIndexBit; assertOperationIsConsistent (_operation); emit Confirmation (msg.sender, _operation);
            }

        }

    }

function reorganizeOwners () private

    {
        uint256 free = 1; while (free < m_numOwners)
        {
            while (free < m_numOwners & & m_owners [free] ! = address (0)) free + +; while (m_numOwners > 1 & & m_owners [m_numOwners] = = address (0)) m_numOwners - -; if (free < m_numOwners & & m_owners [m_numOwners] ! = address (0) & & m_owners [free] =
              = address (0))
            {
                m_owners [free] = m_owners [m_numOwners]; m_ownerIndex [m_owners [free]] = free; m_owners [m_numOwners] = address (0);
            }

        }

    }

function clearPending () private onlyOwner

    {
        uint256 length = m_multiOwnedPendingIndex.length; for (uint256 i = 0; i < length; + + i)
        {
            if (m_multiOwnedPendingIndex [i] ! = 0) delete m_multiOwnedPending [m_multiOwnedPendingIndex [i]];
