        MultiOwnedOperationPendingState storage pending = m_multiOwnedPending [_operation]; assert (0 ! = pending.yetNeeded); assert (m_multiOwnedPendingIndex [pending.index] = = _operation); assert (pending.yetNeeded < = m_multiOwnedRequired);
    }

