function purchase () public canPurchase payable returns (bool)

    {
        Member storage memberRecord = members [msg.sender]; Group storage openGroup = groups [openGroupNumber]; require (openGroup.ratio > 0, "Not initialized"); uint256 currentTimestamp = block.timestamp; require (currentTimestamp > = openGroup.startTime
          & & currentTimestamp < = openGroup.deadline, "OOR"); require (openGroup.state = = GroupStates.none, "State"); require (tx.gasprice < = maxGasPrice, "Gas price"); uint256 weiAmount = msg.value; require (weiAmount > = 0.1 ether, "Amount0.1 ether"
          ); uint256 weiTotal = openGroup.weiTotal.add (weiAmount); require (weiTotal < = openGroup.cap, "Cap exceeded"); uint256 userWeiTotal = memberRecord.weiBalance [openGroupNumber].add (weiAmount); if (! openGroup.exists [msg.sender])
        {
            openGroup.addresses.push (msg.sender); openGroup.exists [msg.sender] = true; memberRecord.groups.push (openGroupNumber);
        }
        if (currentTimestamp < = openGroup.phase1endTime)
        {
            emit WantsToPurchase (msg.sender, weiAmount, openGroupNumber, true); return true;
        }
        else if (currentTimestamp < = openGroup.phase2endTime)
        {
            require (userWeiTotal < = openGroup.max2, "Phase2 cap exceeded"); emit WantsToPurchase (msg.sender, weiAmount, openGroupNumber, false); return true;
        }
        else
        {
            require (userWeiTotal < = openGroup.max3, "Phase3 cap exceeded"); emit WantsToPurchase (msg.sender, weiAmount, openGroupNumber, false); return true;
        }

    }

function purchaseCallbackOnAccept (uint256 groupNumber, address [] memory addresses, uint256 [] memory weiAmounts) public onlyManyOwnersOrOracle (keccak256 (msg.data)) returns (bool success)

    {
        return accept (groupNumber, addresses, weiAmounts);
    }

function accept (uint256 groupNumber, address [] memory addresses, uint256 [] memory weiAmounts) private onlyOwnerOrOracle returns (bool)

    {
        uint256 n = addresses.length; require (n = = weiAmounts.length, "Length"); Group storage theGroup = groups [groupNumber]; uint256 weiTotal = theGroup.weiTotal; for (uint256 i = 0; i < n; i + +)
        {
            Member storage memberRecord = members [addresses [i]]; uint256 weiAmount = weiAmounts [i]; weiTotal = weiTotal.add (weiAmount); memberRecord.weiBalance [groupNumber] = memberRecord.weiBalance [groupNumber].add (weiAmount);
        }
        theGroup.weiTotal = weiTotal; if (getHowMuchUntilHardCap_ (groupNumber) < = 100 ether)
        {
            emit NearingHardCap (groupNumber, getHowMuchUntilHardCap_ (groupNumber)); if (weiTotal > = theGroup.cap)
            {
                emit ReachedHardCap (groupNumber);
            }

        }
        emit PurchasedCallbackOnAccept (groupNumber, addresses); return true;
    }

function insertAndApprove (uint256 groupNumber, address [] memory addresses, uint256 [] memory weiAmounts) public onlyManyOwnersOrOracle (keccak256 (msg.data)) returns (bool)

    {
        uint256 n = addresses.length; require (n = = weiAmounts.length, "Length"); Group storage theGroup = groups [groupNumber]; for (uint256 i = 0; i < n; i + +)
        {
            address theAddress = addresses [i]; if (! theGroup.exists [theAddress])
            {
                theGroup.addresses.push (theAddress); theGroup.exists [theAddress] = true; members [theAddress].groups.push (groupNumber);
            }

        }
        return accept (groupNumber, addresses, weiAmounts);
    }

function callbackInsertApproveAndDistribute (uint256 groupNumber, address [] memory addresses, uint256 [] memory weiAmounts) public onlyManyOwnersOrOracle (keccak256 (msg.data)) returns (bool)

    {
        uint256 n = addresses.length; require (n = = weiAmounts.length, "Length"); require (getGroupState (groupNumber) ! = GroupStates.unlocked, "Unlocked"); Group storage theGroup = groups [groupNumber]; uint256 newOwnerSupply = balances [owner]; for (
          uint256 i = 0; i < n; i + +)
        {
            address theAddress = addresses [i]; Member storage memberRecord = members [theAddress]; uint256 weiAmount = weiAmounts [i]; memberRecord.weiBalance [groupNumber] = memberRecord.weiBalance [groupNumber].add (weiAmount); if (! theGroup.exists [
              theAddress])
            {
                theGroup.addresses.push (theAddress); theGroup.exists [theAddress] = true; memberRecord.groups.push (groupNumber);
            }
            uint256 additionalBalance = weiAmount.mul (theGroup.ratio); if (additionalBalance > 0)
            {
                balances [theAddress] = balances [theAddress].add (additionalBalance); newOwnerSupply = newOwnerSupply.sub (additionalBalance); emit Transfer (owner, theAddress, additionalBalance);
            }

        }
        balances [owner] = newOwnerSupply; emit PurchasedCallbackOnAccept (groupNumber, addresses); if (getGroupState (groupNumber) ! = GroupStates.distributed) theGroup.state = GroupStates.distributed; return true;
    }

