function refund (address [] memory addresses, uint256 [] memory weiAmounts) public onlyManyOwners (keccak256 (msg.data)) returns (bool success)

    {
        uint256 n = addresses.length; require (n = = weiAmounts.length, "Length"); uint256 thePenalty = penalty; uint256 totalRefund = 0; for (uint256 i = 0; i < n; i + +)
        {
            uint256 weiAmount = weiAmounts [i]; address payable theAddress = address (uint160 (address (addresses [i]))); if (thePenalty < weiAmount)
            {
                weiAmount = weiAmount.sub (thePenalty); totalRefund = totalRefund.add (weiAmount); withdrawableBalances [theAddress] = withdrawableBalances [theAddress].add (weiAmount);
            }

        }
