          phase1endEpoch; theGroup.phase2endTime = phase2endEpoch; theGroup.deadline = deadlineEpoch; theGroup.unlockTime = unlockAfterEpoch; theGroup.max2 = phase2weiCap; theGroup.max3 = phase3weiCap; theGroup.cap = hardWeiCap; theGroup.ratio = ratio;
