          distributing) ? "distributing" : (state = = GroupStates.distributed) ? "distributed" : "unlocked"; phase2cap = theGroup.max2; phase3cap = theGroup.max3; cap = theGroup.cap; ratio = theGroup.ratio; startTime = theGroup.startTime; phase1endTime =
