function distributeCallback (uint256 groupNumber, uint256 howMany) public onlyManyOwnersOrOracle (keccak256 (msg.data)) returns (bool success)

    {
        Group storage theGroup = groups [groupNumber]; GroupStates state = getGroupState (groupNumber); require (state < GroupStates.distributed, "Dist"); if (state ! = GroupStates.distributing)
        {
            theGroup.state = GroupStates.distributing;
        }
        uint256 n = theGroup.addresses.length; uint256 nextDistributionIndex = theGroup.nextDistributionIndex; uint256 exclusiveEndIndex = nextDistributionIndex + howMany; if (exclusiveEndIndex > n)
        {
            exclusiveEndIndex = n;
        }
        uint256 newOwnerSupply = balances [owner]; for (uint256 i = nextDistributionIndex; i < exclusiveEndIndex; i + +)
        {
            address theAddress = theGroup.addresses [i]; uint256 balance = getUndistributedBalanceOf_ (theAddress, groupNumber); if (balance > 0)
            {
                balances [theAddress] = balances [theAddress].add (balance); newOwnerSupply = newOwnerSupply.sub (balance); emit Transfer (owner, theAddress, balance);
            }

        }
        balances [owner] = newOwnerSupply; if (exclusiveEndIndex < n)
        {
            emit DistributedBatch (groupNumber, howMany);
        }
        else
        {
            emit ShouldCallDoneDistributing ();
        }
        theGroup.nextDistributionIndex = exclusiveEndIndex; return true;
    }

