function _getAvailablePoll (Poll memory poll) private view returns (uint, uint, uint)

    {
        if (poll.startTime = = 0)
        {
            return (0, 0, 0);
        }
        uint duration = 0; uint amount = 0; uint curTime = now; uint currentDecayPeriod = (curTime - poll.startTime) / fourYears; uint lastDecayPeriod = 0; if (poll.lastMineTime > 0)
        {
            duration = curTime - poll.lastMineTime; lastDecayPeriod = (poll.lastMineTime - poll.startTime) / fourYears;
        }
        else
        {
            duration = curTime - poll.startTime;
        }
        if (currentDecayPeriod = = lastDecayPeriod)
        {
            amount = poll.amountPerMinute * duration / (60 * 2 * * currentDecayPeriod);
        }
        else
        {
            uint right_duration = (curTime - poll.startTime) % fourYears; if (poll.lastMineTime > 0 & & ((poll.lastMineTime - poll.startTime) % fourYears = = 0))
            {
                uint left_duration = fourYears - (poll.lastMineTime - poll.startTime) % fourYears; amount = amount + poll.amountPerMinute * left_duration / (60 * 2 * * lastDecayPeriod);
            }
            amount = amount + poll.amountPerMinute * right_duration / (60 * 2 * * currentDecayPeriod); if (poll.lastMineTime = = 0)
            {
                for (uint i = lastDecayPeriod; i < currentDecayPeriod; i + +)
                {
                    amount = amount + poll.amountPerMinute * fourYears / (60 * 2 * * i);
                }

            }
            else if (poll.lastMineTime > 0 & & ((poll.lastMineTime - poll.startTime) % fourYears = = 0))
            {
                for (uint i = lastDecayPeriod; i < currentDecayPeriod; i + +)
                {
                    amount = amount + poll.amountPerMinute * fourYears / (60 * 2 * * i);
                }

            }
            else
            {
                for (uint i = lastDecayPeriod + 1; i < currentDecayPeriod; i + +)
                {
                    amount = amount + poll.amountPerMinute * fourYears / (60 * 2 * * i);
                }

            }

        }
        uint availableAmount = amount + poll.leftMine; uint totalMine = amount + poll.totalMine; return (currentDecayPeriod, totalMine, availableAmount);
    }

