function mintableSupply () public view returns (uint)

    {
        if (! isMintable ())
        {
            return 0;
        }
        uint index = getCurrentSchedule (); uint amountPreviousPeriod = _remainingSupplyFromPreviousYear (index); ScheduleData memory schedule = schedules [index]; uint weeksInPeriod = (schedule.endPeriod - schedule.startPeriod).div (mintPeriodDuration);
          uint supplyPerWeek = schedule.totalSupply.divideDecimal (weeksInPeriod); uint weeksToMint = lastMintEvent > = schedule.startPeriod ? _numWeeksRoundedDown (now.sub (lastMintEvent)) : _numWeeksRoundedDown (now.sub (schedule.startPeriod)); uint
          amountInPeriod = supplyPerWeek.multiplyDecimal (weeksToMint); return amountInPeriod.add (amountPreviousPeriod);
    }

function _numWeeksRoundedDown (uint _timeDiff) public view returns (uint)

    {
        return _timeDiff.div (mintPeriodDuration);
    }

function isMintable () public view returns (bool)

    {
        bool mintable = false; if (now - lastMintEvent > mintPeriodDuration & & now < = schedules [6].endPeriod)
        {
            mintable = true;
        }
        return mintable;
    }

