    {
        require (now < = schedules [6].endPeriod, "Mintable periods have ended"); for (uint i = 0; i < INFLATION_SCHEDULES_LENGTH; i + +)
        {
            if (schedules [i].startPeriod < = now & & schedules [i].endPeriod > = now)
            {
