            }

        }

    }

function _remainingSupplyFromPreviousYear (uint currentSchedule) internal view returns (uint)

    {
        if (currentSchedule = = 0 | | lastMintEvent > schedules [currentSchedule - 1].endPeriod)
        {
            return 0;
        }
        uint amountInPeriod = schedules [currentSchedule - 1].totalSupply.sub (schedules [currentSchedule - 1].totalSupplyMinted); if (amountInPeriod < 0)
        {
            return 0;
        }
        return amountInPeriod;
    }

function updateMintValues () external onlySynthetix returns (bool)

    {
        uint currentIndex = getCurrentSchedule (); uint lastPeriodAmount = _remainingSupplyFromPreviousYear (currentIndex); uint currentPeriodAmount = mintableSupply ().sub (lastPeriodAmount); if (lastPeriodAmount > 0)
        {
            schedules [currentIndex - 1].totalSupplyMinted = schedules [currentIndex - 1].totalSupplyMinted.add (lastPeriodAmount);
        }
        schedules [currentIndex].totalSupplyMinted = schedules [currentIndex].totalSupplyMinted.add (currentPeriodAmount); lastMintEvent = now; emit SupplyMinted (lastPeriodAmount, currentPeriodAmount, currentIndex, now); return true;
    }

