function internalUpdateRates (bytes4 [] currencyKeys, uint [] newRates, uint timeSent) internal returns (bool)

    {
        require (currencyKeys.length = = newRates.length, "Currency key array length must match rates array length."); require (timeSent < (now + ORACLE_FUTURE_LIMIT), "Time is too far into the future"); for (uint i = 0; i < currencyKeys.length; i + +)
        {
            require (newRates [i] ! = 0, "Zero is not a valid rate, please call deleteRate instead."); require (currencyKeys [i] ! = "sUSD", "Rate of sUSD cannot be updated, it's always UNIT."); if (timeSent < lastRateUpdateTimes [currencyKeys [i]])
            {
                continue;
            }
            newRates [i] = rateOrInverted (currencyKeys [i], newRates [i]); rates [currencyKeys [i]] = newRates [i]; lastRateUpdateTimes [currencyKeys [i]] = timeSent;
        }
        emit RatesUpdated (currencyKeys, newRates); updateXDRRate (timeSent); if (priceUpdateLock)
        {
