function rateOrInverted (bytes4 currencyKey, uint rate) internal returns (uint)

    {
        InversePricing storage inverse = inversePricing [currencyKey]; if (inverse.entryPoint < = 0)
        {
            return rate;
        }
        uint newInverseRate = rates [currencyKey]; if (! inverse.frozen)
        {
            uint doubleEntryPoint = inverse.entryPoint.mul (2); if (doubleEntryPoint < = rate)
            {
                newInverseRate = 0;
            }
            else
            {
                newInverseRate = doubleEntryPoint.sub (rate);
            }
            if (newInverseRate > = inverse.upperLimit)
            {
                newInverseRate = inverse.upperLimit;
            }
            else if (newInverseRate < = inverse.lowerLimit)
            {
                newInverseRate = inverse.lowerLimit;
            }
            if (newInverseRate = = inverse.upperLimit | | newInverseRate = = inverse.lowerLimit)
            {
                inverse.frozen = true; emit InversePriceFrozen (currencyKey);
            }

        }
        return newInverseRate;
    }

function updateXDRRate (uint timeSent) internal

    {
        uint total = 0; for (uint i = 0; i < xdrParticipants.length; i + +)
        {
            total = rates [xdrParticipants [i]].add (total);
        }
        rates ["XDR"] = total; lastRateUpdateTimes ["XDR"] = timeSent; bytes4 [] memory eventCurrencyCode = new bytes4 [] (1); eventCurrencyCode [0] = "XDR"; uint [] memory eventRate = new uint [] (1); eventRate [0] = rates ["XDR"]; emit RatesUpdated (
          eventCurrencyCode, eventRate);
