          "Synthetix is invalid destination"); require (destinationAddress ! = address (proxy), "Proxy is invalid destination"); synths [sourceCurrencyKey].burn (from, sourceAmount); uint destinationAmount = effectiveValue (sourceCurrencyKey, sourceAmount
          , destinationCurrencyKey); uint amountReceived = destinationAmount; uint fee = 0; if (chargeFee)
