          debt < debtToRemove ? debt : debtToRemove; _removeFromDebtRegister (amountToRemove); uint amountToBurn = debtInCurrencyKey < amount ? debtInCurrencyKey : amount; synths [currencyKey].burn (messageSender, amountToBurn);
