    }

function debtBalanceOf (address issuer, bytes4 currencyKey) public view returns (uint)

    {
        uint initialDebtOwnership; uint debtEntryIndex; (initialDebtOwnership, debtEntryIndex) = synthetixState.issuanceData (issuer); if (initialDebtOwnership = = 0) return 0; uint currentDebtOwnership = synthetixState.lastDebtLedgerEntry ().
          divideDecimalRoundPrecise (synthetixState.debtLedger (debtEntryIndex)).multiplyDecimalRoundPrecise (initialDebtOwnership); uint totalSystemValue = totalIssuedSynths (currencyKey); uint highPrecisionBalance = totalSystemValue.
          decimalToPreciseDecimal ().multiplyDecimalRoundPrecise (currentDebtOwnership); return highPrecisionBalance.preciseDecimalToDecimal ();
    }

