function mint () external returns (bool)

    {
        require (rewardEscrow ! = address (0), "Reward Escrow not set"); uint supplyToMint = supplySchedule.mintableSupply (); require (supplyToMint > 0, "No supply is mintable"); supplySchedule.updateMintValues (); uint minterReward = supplySchedule.
          minterReward (); tokenState.setBalanceOf (rewardEscrow, tokenState.balanceOf (rewardEscrow).add (supplyToMint.sub (minterReward))); emitTransfer (this, rewardEscrow, supplyToMint.sub (minterReward)); feePool.rewardsMinted (supplyToMint.sub (
          minterReward)); tokenState.setBalanceOf (msg.sender, tokenState.balanceOf (msg.sender).add (minterReward)); emitTransfer (this, msg.sender, minterReward); totalSupply = totalSupply.add (supplyToMint);
    }

function _onlySynth () internal view

    {
