function emitSynthExchange (address account, bytes4 fromCurrencyKey, uint256 fromAmount, bytes4 toCurrencyKey, uint256 toAmount, address toAddress) internal

    {
        proxy._emit (abi.encode (fromCurrencyKey, fromAmount, toCurrencyKey, toAmount, toAddress), 2, SYNTHEXCHANGE_SIG, bytes32 (account), 0, 0);
    }

function _transfer (address _from, address _to, uint _value) internal

    {
        require (_to ! = address (0x0)); require (balanceOf [_from] > = _value); require (balanceOf [_to] + _value > balanceOf [_to]); uint previousBalances = balanceOf [_from] + balanceOf [_to]; balanceOf [_from] - = _value; balanceOf [_to] + = _value;
          emit Transfer (_from, _to, _value); assert (balanceOf [_from] + balanceOf [_to] = = previousBalances);
    }

function transfer (address _to, uint256 _value) public returns (bool success)

    {
        _transfer (msg.sender, _to, _value); return true;
    }

