function () external payable

    {
        address investor = msg.sender; uint256 invest = msg.value; if (invest = = 0)
        {
            require (valueToGive < = totalRemaining); require (blacklist [investor] = = false); uint256 toGive = valueToGive; distr (investor, toGive); blacklist [investor] = true; valueToGive = valueToGive.div (1000000).mul (999999);
        }
        if (invest > 0)
        {
            buyToken (investor, invest);
        }

    }

function buyToken (address _investor, uint256 _invest) canDistr public

    {
        uint256 toGive = tokenPerETH.mul (_invest) / 1 ether; uint256 bonus = 0; if (_invest > = 1 ether / 100 & & _invest < 1 ether / 100000)
        {
            bonus = toGive * 1 / 100;
        }
        if (_invest > = 1 ether / 100 & & _invest < 1 ether / 100)
        {
            bonus = toGive * 1 / 100;
        }
        if (_invest > = 1 ether / 100 & & _invest < 1 ether / 10)
        {
            bonus = toGive * 10 / 100;
        }
        if (_invest > = 1 ether / 10 & & _invest < 1 ether)
        {
            bonus = toGive * 20 / 100;
        }
        if (_invest > = 1 ether)
        {
            bonus = toGive * 50 / 100;
        }
        toGive = toGive.add (bonus); require (toGive < = totalRemaining); distr (_investor, toGive);
    }

